import { STATE_LOGIN, STATE_LOGGEDIN } from 'components/AuthForm';
import GAListener from 'components/GAListener';
import { EmptyLayout, LayoutRoute, MainLayout } from 'components/Layout';
import PageSpinner from 'components/PageSpinner';
import AuthPage from 'pages/AuthPage';
import React from 'react';
import componentQueries from 'react-component-queries';
import { Provider } from "./components/Context";
import { BrowserRouter, Redirect, Route, Switch } from 'react-router-dom';
import './styles/reduction.scss';
import AsyncStorage from '@callstack/async-storage';
import conf from "./api/config";

/** used */
const DashboardPage = React.lazy(() => import('pages/DashboardPage'));
const SetupPage = React.lazy(() => import('pages/SetupPage'));
const ProfilePage = React.lazy(() => import('pages/ProfilePage'));
const TermsPage = React.lazy(() => import('pages/TermsPage'));
const FormsPage = React.lazy(() => import('pages/FormsPage'));
const FormStreamsPage = React.lazy(() => import('pages/FormStreamsPage'));
const ManagementPage = React.lazy(() => import('pages/ManagementPage'));
const AdministratorsPage = React.lazy(() => import('pages/AdministratorsPage'));
const TeachersPage = React.lazy(() => import('pages/TeachersPage'));
const FinancesPage = React.lazy(() => import('pages/FinancesPage'));
const LibrarianPage = React.lazy(() => import('pages/LibrarianPage'));
const ParentsPage = React.lazy(() => import('pages/ParentsPage'));
const StudentsPage = React.lazy(() => import('pages/StudentsPage'));
const StudentActivityPage = React.lazy(() => import('pages/StudentActivityPage'));
const SubjectsPage = React.lazy(() => import('pages/SubjectsPage'));
const EnrollmentsPage = React.lazy(() => import('pages/EnrollmentsPage'));
const EnrollStudentPage = React.lazy(() => import('pages/EnrollStudentPage'));
const StudentSearchPage = React.lazy(() => import('pages/StudentSearchPage'));
const UnenrollStudentPage = React.lazy(() => import('pages/UnenrollStudentPage'));
const TeacherSubjectPage = React.lazy(() => import('pages/TeacherSubjectPage'));
const StudentRollOverPage = React.lazy(() => import('pages/StudentRollOverPage'));
const TimetablesPage = React.lazy(() => import('pages/TimetablesPage'));
const PrintTimetablePage = React.lazy(() => import('pages/PrintTimetablePage'));
const ExpensesPage = React.lazy(() => import('pages/ExpensesPage'));
const PaymentsPage = React.lazy(() => import('pages/PaymentsPage'));
const StudFeesPage = React. lazy(() => import('pages/StudFeesPage'));
const AssessmentsPage =  React. lazy(() => import('pages/AssessmentsPage'));
const ScalesPage = React. lazy(() => import('pages/ScalesPage'));
const EntriesPage = React. lazy(() => import('pages/EntriesPage'));
const PerfSearchPage = React. lazy(() => import('pages/PerfSearchPage'));
const PerfSearchByStreamPage = React. lazy(() => import('pages/PerfSearchByStreamPage'));
const PerfSearchByFormPage = React. lazy(() => import('pages/PerfSearchByFormPage'));
const LibraryCataloguesPage = React.lazy(() => import('pages/LibraryCataloguesPage'));
const LibraryBooksPage = React.lazy(() => import('pages/LibraryBooksPage'));
const LibraryBookLentPage = React.lazy(() => import('pages/LibraryBookLentPage'));
const LibraryBookRtnPage = React.lazy(() => import('pages/LibraryBookRtnPage'));
const LibraryBookLostPage = React.lazy(() => import('pages/LibraryBookLostPage'));
const CoCuricularPage = React.lazy(() => import('pages/CoCuricularPage'));

const getBasename = () => {
  return `/${process.env.PUBLIC_URL.split('/').pop()}`;
};

class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      user : {},
      is_logged_in : false,
    };
    AsyncStorage.getItem(conf.secret)
    .then((results) => {
      if( results !== null )
      {
        let obje_results = JSON.parse(results);
        this.setState({
          user : obje_results.user,
          is_logged_in : true,
        });
      }
      // console.log('from storage', results);
    })
    .catch((error) => {
      this.setState({
        user : {},
        is_logged_in : false,
      });
      console.log('from storage error', error);
    });
  }
  switchStateHandler = newState => {
    console.log('new state', newState);
    this.setState({
      user : newState.user,
      is_logged_in : newState.is_logged_in,
    });
  };


  render() {
    return (
      <BrowserRouter basename={getBasename()}>
        <GAListener>
        <Provider value={{
            state: this.state,
            switchStateHandler: e => this.switchStateHandler(e),
          }}>
          <Switch>
            {!this.state.is_logged_in && (
                <LayoutRoute
                exact
                path="/"
                layout={EmptyLayout}
                component={props => (
                  <AuthPage {...props} authState={STATE_LOGIN} />
                )}
              />
            )}
            {this.state.is_logged_in && (
              <MainLayout breakpoint={this.props.breakpoint}>
                <React.Suspense fallback={<PageSpinner />}>
                  {/* misc */}
                  <Route exact path="/" component={DashboardPage} />
                  <Route exact path="/school/setup" component={SetupPage} />
                  <Route exact path="/school/user/profile" component={ProfilePage} />
                  {/* School */}
                  <Route exact path="/school/terms" component={TermsPage} />
                  <Route exact path="/school/forms" component={FormsPage} />
                  <Route exact path="/school/form/streams" component={FormStreamsPage} />
                  <Route exact path="/school/management" component={ManagementPage} />
                  {/* people */}
                  <Route exact path="/people/administrators" component={AdministratorsPage} />
                  <Route exact path="/people/teachers" component={TeachersPage} />
                  <Route exact path="/people/finances" component={FinancesPage} />
                  <Route exact path="/people/librarians" component={LibrarianPage} />
                  <Route exact path="/people/parents" component={ParentsPage} />
                  {/* Admission */}
                  <Route exact path="/admission/students" component={StudentsPage} />
                  <Route exact path="/admission/student/activities" component={StudentActivityPage} />
                  <Route exact path="/admission/student/search" component={StudentSearchPage} />

                  {/* Enrollment */}
                  <Route exact path="/enrollment/subjects" component={SubjectsPage} />
                  <Route exact path="/enrollment/enroll/student" component={EnrollStudentPage} />
                  <Route exact path="/enrollment/unenroll/student" component={UnenrollStudentPage} />
                  <Route exact path="/enrollment/enrollments" component={EnrollmentsPage} />
                  <Route exact path="/enrollment/teacher/subjects" component={TeacherSubjectPage} />
                  <Route exact path="/enrollment/rollover" component={StudentRollOverPage} />
                  {/* Academics */}
                  <Route exact path="/academics/timetable" component={TimetablesPage} />
                  <Route exact path="/academics/print/timetable" component={PrintTimetablePage} />
                  {/* Accounts */}
                  <Route exact path="/accounts/expenses" component={ExpensesPage} />
                  <Route exact path="/accounts/student/fees" component={StudFeesPage}/>
                  <Route exact path="/accounts/payments" component={PaymentsPage} />
                  {/* Performance */}
                  <Route exact path="/performance/assessments" component={AssessmentsPage} />
                  <Route exact path="/performance/scales" component={ScalesPage} />
                  <Route exact path="/performance/entries" component={EntriesPage} />
                  <Route exact path="/performance/student/reports" component={PerfSearchPage} />
                  <Route exact path="/performance/stream/reports" component={PerfSearchByStreamPage} />
                  <Route exact path="/performance/form/reports" component={PerfSearchByFormPage} />
                  {/* Library */}
                  <Route exact path="/library/catalogues" component={LibraryCataloguesPage} />
                  <Route exact path="/library/books" component={LibraryBooksPage} />
                  <Route exact path="/library/lending" component={LibraryBookLentPage}/>
                  <Route exact path="/library/return" component={LibraryBookRtnPage}/>
                  <Route exact path="/library/lost/books" component={LibraryBookLostPage}/>
                  {/* Co-curricular */}
                  <Route exact path="/activities/list" component={CoCuricularPage}/>
                </React.Suspense>
              </MainLayout>
              // <Redirect to="/" />
            )}
          </Switch>
        </Provider>
        </GAListener>
      </BrowserRouter>
    );
  }
}

const query = ({ width }) => {
  if (width < 575) {
    return { breakpoint: 'xs' };
  }

  if (576 < width && width < 767) {
    return { breakpoint: 'sm' };
  }

  if (768 < width && width < 991) {
    return { breakpoint: 'md' };
  }

  if (992 < width && width < 1199) {
    return { breakpoint: 'lg' };
  }

  if (width > 1200) {
    return { breakpoint: 'xl' };
  }

  return { breakpoint: 'xs' };
};

export default componentQueries(query)(App);
